current.global_css:
:root {
    --input-font-size: 1.3rem;

    .bls__section {
        --bls_product-item-vertical-space: clamp(2rem, 1vw, 2rem);
    }
}

body .spr-badge-starrating .spr-icon {
    color: #FFB800;
}

.hover-zoom,
.bls__product-banner a {
    border-radius: 5px;
}

body .bls__pre-order-label {
    --product-label-background-color: #F8BA26;
    --product-label-color: #111;
}

:root {
    --btn-text-transform: capitalize;
    --btn-padding: 1.2rem 5.5rem;
}

@media (min-width: 1025px) {
    html body .page-header {
        border-bottom: 1px solid var(--border-color-base);
    }
}

.bls__slide-items .slide-items .slide-bg-image {
    border-radius: 20px;
    overflow: hidden;
}

@media (min-width: 1200px) {
    .bls__slide-content.left_position .sf__slide-content.text-md-left {
        padding-left: clamp(1rem, 3%, 8.5rem);
    }
}

@media (min-width: 1600px) {
    .bls__slide-content.left_position .sf__slide-content.text-md-left {
        padding-left: clamp(1rem, 10%, 13rem);
    }
}

/* Disable legacy login popup and redirect to new customer accounts */
.bls__account-popup {
    display: none !important;
}

.bls__account-modal {
    display: none !important;
}

.account-popup-modal {
    display: none !important;
}

.login-modal {
    display: none !important;
}

.modal-account {
    display: none !important;
}

.account-modal {
    display: none !important;
}

.popup-account {
    display: none !important;
}

.modal-login {
    display: none !important;
}

.login-popup {
    display: none !important;
}

/* Hide any modal overlays that might be associated with account login */
.modal-backdrop {
    display: none !important;
}

.account-backdrop {
    display: none !important;
}
